def get_patient_protocol_from_db(patient_id):
    try:
        from database import get_conn

        conn = get_conn()
        row = conn.execute("SELECT protocol FROM patients WHERE id=?", (patient_id,)).fetchone()
        conn.close()
        return row["protocol"] if row and row["protocol"] else ""
    except Exception:
        return ""


@st.cache_data
def load_exercises():
    path = Path("assets/exercises.json")
    if not path.exists():
        return []
    with path.open("r", encoding="utf-8") as f:
        return json.load(f).get("exercises", [])


@st.cache_data
def load_reference(path):
    p = Path(path)
    return np.load(str(p)) if p.exists() else None


@st.cache_data
def detect_cameras():
    available = []
    for i in range(5):
        cap = cv2.VideoCapture(i)
        if cap.isOpened():
            ret, _ = cap.read()
            if ret:
                available.append(i)
            cap.release()
    return available if available else [0]


