def detect_rep(angles, exercise_id, in_progress):
    if exercise_id in ("knee_flexion", "squat", "lunge"):
        a = angles.get("genou_gauche", 180)
        if not in_progress and a < 120:
            return True, True
        if in_progress and a > 155:
            return False, False
    elif exercise_id in ("arm_raise", "lateral_raise"):
        a = angles.get("epaule_gauche", 0)
        if not in_progress and a > 130:
            return True, True
        if in_progress and a < 30:
            return False, False
    elif exercise_id == "trunk_rotation":
        a = angles.get("epaule_gauche", 90)
        if not in_progress and a < 50:
            return True, True
        if in_progress and a > 80:
            return False, False
    elif exercise_id == "hip_extension":
        a = angles.get("hanche_gauche", 180)
        if not in_progress and a > 150:
            return True, True
        if in_progress and a < 100:
            return False, False
    elif exercise_id == "bicep_curl":
        a = angles.get("coude_gauche", 180)
        if not in_progress and a < 60:
            return True, True
        if in_progress and a > 140:
            return False, False
    elif exercise_id == "good_morning":
        a = angles.get("hanche_gauche", 180)
        if not in_progress and a < 90:
            return True, True
        if in_progress and a > 155:
            return False, False
    return False, in_progress


def score_color_class(score):
    if score >= 75:
        return "score-good"
    if score >= 50:
        return "score-mid"
    return "score-bad"


def build_feedback_overlay(messages):
    if not messages:
        return ""
    items = ""
    for msg in messages[:3]:
        is_warn = any(word in msg.lower() for word in ["attention", "douleur", "arret", "arrêt", "stop"])
        cls = "feedback-popup warn" if is_warn else "feedback-popup"
        title = "Attention" if is_warn else "Conseil"
        text = msg[:120] + ("..." if len(msg) > 120 else "")
        items += f"""
        <div class="{cls}">
          <div class="feedback-popup-title">{title}</div>
          {text}
        </div>
        """
    return f'<div class="feedback-overlay">{items}</div>'


